		internal static int TagToInt(this string s)
		{
			if (string.IsNullOrEmpty(s))
			{
				return 0;
			}
			return (int)(((uint)s[0] << 24) | ((uint)s[1] << 16) | ((uint)s[2] << 8) | s[3]);
		}

		public static int[] ToIntArray(this string text)
