		private TweenRunner<FloatTween> m_AlphaTweenRunner;

		private bool validTemplate;

		private Coroutine m_Coroutine;

		private static OptionData s_NoOptionData = new OptionData();

		public RectTransform template
		{
			get
			{
				return m_Template;
			}
