				}
				if (m_GlyphsToAddLookup.Add(glyphIndex))
				{
					m_GlyphsToAdd.Add(glyphIndex);
				}
				if (m_CharactersToAddLookup.Add(codePoint))
				{
					m_CharactersToAdd.Add(tMP_Character);
				}
			}
			if (m_GlyphsToAdd.Count == 0)
