				m_CharacterTable.Add(tMP_Character2);
				m_CharacterLookupDictionary.Add(tMP_Character2.unicode, tMP_Character2);
				m_CharactersToAdd.RemoveAt(k);
				k--;
			}
			if (m_IsMultiAtlasTexturesEnabled && !flag2)
			{
				while (!flag2)
				{
