				m_VerticalScrollbar.value = GetScrollPositionRelativeToViewport();
			}
		}

		private void OnScrollbarValueChange(float value)
		{
			if (!(value < 0f) && !(value > 1f))
			{
				AdjustTextPositionRelativeToViewport(value);
				m_ScrollPosition = value;
			}
		}

