		public void ResizeMeshInfo(int size)
		{
			size = Mathf.Min(size, 16383);
			int newSize = size * 4;
			int newSize2 = size * 6;
			int num = vertices.Length / 4;
			Array.Resize(ref vertices, newSize);
			Array.Resize(ref normals, newSize);
			Array.Resize(ref tangents, newSize);
			Array.Resize(ref uvs0, newSize);
			Array.Resize(ref uvs2, newSize);
			Array.Resize(ref colors32, newSize);
			Array.Resize(ref triangles, newSize2);
			if (size <= num)
			{
				mesh.triangles = triangles;
				mesh.vertices = vertices;
				mesh.normals = normals;
				mesh.tangents = tangents;
				return;
			}
			for (int i = num; i < size; i++)
			{
				int num2 = i * 4;
				int num3 = i * 6;
				normals[num2] = s_DefaultNormal;
				normals[1 + num2] = s_DefaultNormal;
				normals[2 + num2] = s_DefaultNormal;
				normals[3 + num2] = s_DefaultNormal;
				tangents[num2] = s_DefaultTangent;
				tangents[1 + num2] = s_DefaultTangent;
				tangents[2 + num2] = s_DefaultTangent;
				tangents[3 + num2] = s_DefaultTangent;
				triangles[num3] = num2;
				triangles[1 + num3] = 1 + num2;
				triangles[2 + num3] = 2 + num2;
				triangles[3 + num3] = 2 + num2;
				triangles[4 + num3] = 3 + num2;
				triangles[5 + num3] = num2;
			}
			mesh.vertices = vertices;
			mesh.normals = normals;
			mesh.tangents = tangents;
			mesh.triangles = triangles;
		}

		public void ResizeMeshInfo(int size, bool isVolumetric)
		{
			int num = ((!isVolumetric) ? 4 : 8);
			int num2 = ((!isVolumetric) ? 6 : 36);
			size = Mathf.Min(size, 65532 / num);
			int newSize = size * num;
			int newSize2 = size * num2;
			int num3 = vertices.Length / num;
			Array.Resize(ref vertices, newSize);
			Array.Resize(ref normals, newSize);
			Array.Resize(ref tangents, newSize);
			Array.Resize(ref uvs0, newSize);
			Array.Resize(ref uvs2, newSize);
			Array.Resize(ref colors32, newSize);
			Array.Resize(ref triangles, newSize2);
			if (size <= num3)
			{
				mesh.triangles = triangles;
				mesh.vertices = vertices;
				mesh.normals = normals;
				mesh.tangents = tangents;
				return;
			}
			for (int i = num3; i < size; i++)
			{
				int num4 = i * num;
				int num5 = i * num2;
				normals[num4] = s_DefaultNormal;
				normals[1 + num4] = s_DefaultNormal;
				normals[2 + num4] = s_DefaultNormal;
				normals[3 + num4] = s_DefaultNormal;
				tangents[num4] = s_DefaultTangent;
				tangents[1 + num4] = s_DefaultTangent;
				tangents[2 + num4] = s_DefaultTangent;
				tangents[3 + num4] = s_DefaultTangent;
				if (isVolumetric)
				{
					normals[4 + num4] = s_DefaultNormal;
					normals[5 + num4] = s_DefaultNormal;
					normals[6 + num4] = s_DefaultNormal;
					normals[7 + num4] = s_DefaultNormal;
					tangents[4 + num4] = s_DefaultTangent;
					tangents[5 + num4] = s_DefaultTangent;
					tangents[6 + num4] = s_DefaultTangent;
					tangents[7 + num4] = s_DefaultTangent;
				}
				triangles[num5] = num4;
				triangles[1 + num5] = 1 + num4;
				triangles[2 + num5] = 2 + num4;
				triangles[3 + num5] = 2 + num4;
				triangles[4 + num5] = 3 + num4;
				triangles[5 + num5] = num4;
				if (isVolumetric)
				{
					triangles[num5 + 6] = num4 + 4;
					triangles[num5 + 7] = num4 + 5;
					triangles[num5 + 8] = num4 + 1;
					triangles[num5 + 9] = num4 + 1;
					triangles[num5 + 10] = num4;
					triangles[num5 + 11] = num4 + 4;
					triangles[num5 + 12] = num4 + 3;
					triangles[num5 + 13] = num4 + 2;
					triangles[num5 + 14] = num4 + 6;
					triangles[num5 + 15] = num4 + 6;
					triangles[num5 + 16] = num4 + 7;
					triangles[num5 + 17] = num4 + 3;
					triangles[num5 + 18] = num4 + 1;
					triangles[num5 + 19] = num4 + 5;
					triangles[num5 + 20] = num4 + 6;
					triangles[num5 + 21] = num4 + 6;
					triangles[num5 + 22] = num4 + 2;
					triangles[num5 + 23] = num4 + 1;
					triangles[num5 + 24] = num4 + 4;
					triangles[num5 + 25] = num4;
					triangles[num5 + 26] = num4 + 3;
					triangles[num5 + 27] = num4 + 3;
					triangles[num5 + 28] = num4 + 7;
					triangles[num5 + 29] = num4 + 4;
					triangles[num5 + 30] = num4 + 7;
					triangles[num5 + 31] = num4 + 6;
					triangles[num5 + 32] = num4 + 5;
					triangles[num5 + 33] = num4 + 5;
					triangles[num5 + 34] = num4 + 4;
					triangles[num5 + 35] = num4 + 7;
				}
			}
			mesh.vertices = vertices;
			mesh.normals = normals;
			mesh.tangents = tangents;
			mesh.triangles = triangles;
		}

		public void Clear()
		{
			if (vertices != null)
			{
				Array.Clear(vertices, 0, vertices.Length);
				vertexCount = 0;
				if (mesh != null)
				{
					mesh.vertices = vertices;
				}
			}
		}

		public void Clear(bool uploadChanges)
		{
			if (vertices != null)
			{
				Array.Clear(vertices, 0, vertices.Length);
				vertexCount = 0;
				if (uploadChanges && mesh != null)
				{
					mesh.vertices = vertices;
				}
				if (mesh != null)
				{
					mesh.bounds = s_DefaultBounds;
				}
			}
		}

		public void ClearUnusedVertices()
		{
			int num = vertices.Length - vertexCount;
			if (num > 0)
			{
				Array.Clear(vertices, vertexCount, num);
			}
		}

		public void ClearUnusedVertices(int startIndex)
		{
			int num = vertices.Length - startIndex;
			if (num > 0)
			{
				Array.Clear(vertices, startIndex, num);
			}
		}

		public void ClearUnusedVertices(int startIndex, bool updateMesh)
		{
			int num = vertices.Length - startIndex;
			if (num > 0)
			{
				Array.Clear(vertices, startIndex, num);
			}
			if (updateMesh && mesh != null)
			{
				mesh.vertices = vertices;
			}
		}

		public void SortGeometry(VertexSortingOrder order)
		{
			if (order == VertexSortingOrder.Normal || order != VertexSortingOrder.Reverse)
			{
				return;
			}
			int num = vertexCount / 4;
			for (int i = 0; i < num; i++)
			{
				int num2 = i * 4;
				int num3 = (num - i - 1) * 4;
				if (num2 < num3)
				{
					SwapVertexData(num2, num3);
				}
			}
		}

		public void SortGeometry(IList<int> sortingOrder)
		{
			int count = sortingOrder.Count;
			if (count * 4 > vertices.Length)
			{
				return;
			}
			for (int i = 0; i < count; i++)
			{
				int num;
				for (num = sortingOrder[i]; num < i; num = sortingOrder[num])
				{
				}
				if (num != i)
				{
					SwapVertexData(num * 4, i * 4);
				}
			}
		}

		public void SwapVertexData(int src, int dst)
		{
			Vector3 vector = vertices[dst];
			vertices[dst] = vertices[src];
			vertices[src] = vector;
			vector = vertices[dst + 1];
			vertices[dst + 1] = vertices[src + 1];
			vertices[src + 1] = vector;
			vector = vertices[dst + 2];
			vertices[dst + 2] = vertices[src + 2];
			vertices[src + 2] = vector;
			vector = vertices[dst + 3];
			vertices[dst + 3] = vertices[src + 3];
			vertices[src + 3] = vector;
			Vector4 vector2 = uvs0[dst];
			uvs0[dst] = uvs0[src];
			uvs0[src] = vector2;
			vector2 = uvs0[dst + 1];
			uvs0[dst + 1] = uvs0[src + 1];
			uvs0[src + 1] = vector2;
			vector2 = uvs0[dst + 2];
			uvs0[dst + 2] = uvs0[src + 2];
			uvs0[src + 2] = vector2;
			vector2 = uvs0[dst + 3];
			uvs0[dst + 3] = uvs0[src + 3];
			uvs0[src + 3] = vector2;
			vector2 = uvs2[dst];
			uvs2[dst] = uvs2[src];
			uvs2[src] = vector2;
			vector2 = uvs2[dst + 1];
			uvs2[dst + 1] = uvs2[src + 1];
			uvs2[src + 1] = vector2;
			vector2 = uvs2[dst + 2];
			uvs2[dst + 2] = uvs2[src + 2];
			uvs2[src + 2] = vector2;
			vector2 = uvs2[dst + 3];
			uvs2[dst + 3] = uvs2[src + 3];
			uvs2[src + 3] = vector2;
			Color32 color = colors32[dst];
			colors32[dst] = colors32[src];
			colors32[src] = color;
			color = colors32[dst + 1];
			colors32[dst + 1] = colors32[src + 1];
			colors32[src + 1] = color;
			color = colors32[dst + 2];
			colors32[dst + 2] = colors32[src + 2];
			colors32[src + 2] = color;
			color = colors32[dst + 3];
			colors32[dst + 3] = colors32[src + 3];
			colors32[src + 3] = color;
		}
	}
	internal class TMP_ObjectPool<T> where T : new()
	{
		private readonly Stack<T> m_Stack = new Stack<T>();

		private readonly UnityAction<T> m_ActionOnGet;

		private readonly UnityAction<T> m_ActionOnRelease;

		public int countAll { get; private set; }

		public int countActive => countAll - countInactive;

		public int countInactive => m_Stack.Count;

		public TMP_ObjectPool(UnityAction<T> actionOnGet, UnityAction<T> actionOnRelease)
		{
			m_ActionOnGet = actionOnGet;
			m_ActionOnRelease = actionOnRelease;
		}

		public T Get()
		{
			T val;
			if (m_Stack.Count == 0)
			{
				val = new T();
				countAll++;
			}
			else
			{
				val = m_Stack.Pop();
			}
			if (m_ActionOnGet != null)
			{
				m_ActionOnGet(val);
			}
			return val;
		}

		public void Release(T element)
		{
			if (m_Stack.Count > 0 && (object)m_Stack.Peek() == (object)element)
			{
				UnityEngine.Debug.LogError("Internal error. Trying to destroy object that is already released to pool.");
			}
			if (m_ActionOnRelease != null)
			{
				m_ActionOnRelease(element);
			}
			m_Stack.Push(element);
		}
	}
	public class TMP_ResourceManager
	{
		private struct FontAssetRef(int nameHashCode, int familyNameHashCode, int styleNameHashCode, TMP_FontAsset fontAsset)
		{
			public int nameHashCode = ((nameHashCode != 0) ? nameHashCode : familyNameHashCode);

			public int familyNameHashCode = familyNameHashCode;

			public int styleNameHashCode = styleNameHashCode;

			public long familyNameAndStyleHashCode = ((long)styleNameHashCode << 32) | (uint)familyNameHashCode;

			public readonly TMP_FontAsset fontAsset = fontAsset;
		}

		private static TMP_Settings s_TextSettings;

		private static readonly Dictionary<int, FontAssetRef> s_FontAssetReferences = new Dictionary<int, FontAssetRef>();

		private static readonly Dictionary<int, TMP_FontAsset> s_FontAssetNameReferenceLookup = new Dictionary<int, TMP_FontAsset>();

		private static readonly Dictionary<long, TMP_FontAsset> s_FontAssetFamilyNameAndStyleReferenceLookup = new Dictionary<long, TMP_FontAsset>();

		private static readonly List<int> s_FontAssetRemovalList = new List<int>(16);

		private static readonly int k_RegularStyleHashCode = TMP_TextUtilities.GetHashCode("Regular");

		internal static TMP_Settings GetTextSettings()
		{
			if (s_TextSettings == null)
			{
				s_TextSettings = Resources.Load<TMP_Settings>("TextSettings");
			}
			return s_TextSettings;
		}

		public static void AddFontAsset(TMP_FontAsset fontAsset)
		{
			int instanceID = fontAsset.instanceID;
			if (!s_FontAssetReferences.ContainsKey(instanceID))
			{
				FontAssetRef value = new FontAssetRef(fontAsset.hashCode, fontAsset.familyNameHashCode, fontAsset.styleNameHashCode, fontAsset);
				s_FontAssetReferences.Add(instanceID, value);
				if (!s_FontAssetNameReferenceLookup.ContainsKey(value.nameHashCode))
				{
					s_FontAssetNameReferenceLookup.Add(value.nameHashCode, fontAsset);
				}
				if (!s_FontAssetFamilyNameAndStyleReferenceLookup.ContainsKey(value.familyNameAndStyleHashCode))
				{
					s_FontAssetFamilyNameAndStyleReferenceLookup.Add(value.familyNameAndStyleHashCode, fontAsset);
				}
				return;
			}
			FontAssetRef value2 = s_FontAssetReferences[instanceID];
			if (value2.nameHashCode == fontAsset.hashCode && value2.familyNameHashCode == fontAsset.familyNameHashCode && value2.styleNameHashCode == fontAsset.styleNameHashCode)
			{
				return;
			}
			if (value2.nameHashCode != fontAsset.hashCode)
			{
				s_FontAssetNameReferenceLookup.Remove(value2.nameHashCode);
				value2.nameHashCode = fontAsset.hashCode;
				if (!s_FontAssetNameReferenceLookup.ContainsKey(value2.nameHashCode))
				{
					s_FontAssetNameReferenceLookup.Add(value2.nameHashCode, fontAsset);
				}
			}
			if (value2.familyNameHashCode != fontAsset.familyNameHashCode || value2.styleNameHashCode != fontAsset.styleNameHashCode)
			{
				s_FontAssetFamilyNameAndStyleReferenceLookup.Remove(value2.familyNameAndStyleHashCode);
				value2.familyNameHashCode = fontAsset.familyNameHashCode;
				value2.styleNameHashCode = fontAsset.styleNameHashCode;
				value2.familyNameAndStyleHashCode = ((long)fontAsset.styleNameHashCode << 32) | (uint)fontAsset.familyNameHashCode;
				if (!s_FontAssetFamilyNameAndStyleReferenceLookup.ContainsKey(value2.familyNameAndStyleHashCode))
				{
					s_FontAssetFamilyNameAndStyleReferenceLookup.Add(value2.familyNameAndStyleHashCode, fontAsset);
				}
			}
			s_FontAssetReferences[instanceID] = value2;
		}

		public static void RemoveFontAsset(TMP_FontAsset fontAsset)
		{
			int instanceID = fontAsset.instanceID;
			if (s_FontAssetReferences.TryGetValue(instanceID, out var value))
			{
				s_FontAssetNameReferenceLookup.Remove(value.nameHashCode);
				s_FontAssetFamilyNameAndStyleReferenceLookup.Remove(value.familyNameAndStyleHashCode);
				s_FontAssetReferences.Remove(instanceID);
			}
		}

		internal static bool TryGetFontAssetByName(int nameHashcode, out TMP_FontAsset fontAsset)
		{
			fontAsset = null;
			return s_FontAssetNameReferenceLookup.TryGetValue(nameHashcode, out fontAsset);
		}

		internal static bool TryGetFontAssetByFamilyName(int familyNameHashCode, int styleNameHashCode, out TMP_FontAsset fontAsset)
		{
			fontAsset = null;
			if (styleNameHashCode == 0)
			{
				styleNameHashCode = k_RegularStyleHashCode;
			}
			long key = ((long)styleNameHashCode << 32) | (uint)familyNameHashCode;
			return s_FontAssetFamilyNameAndStyleReferenceLookup.TryGetValue(key, out fontAsset);
		}

		public static void ClearFontAssetGlyphCache()
		{
			RebuildFontAssetCache();
		}

		internal static void RebuildFontAssetCache()
		{
			foreach (KeyValuePair<int, FontAssetRef> s_FontAssetReference in s_FontAssetReferences)
			{
				FontAssetRef value = s_FontAssetReference.Value;
				TMP_FontAsset fontAsset = value.fontAsset;
				if (fontAsset == null)
				{
					s_FontAssetNameReferenceLookup.Remove(value.nameHashCode);
					s_FontAssetFamilyNameAndStyleReferenceLookup.Remove(value.familyNameAndStyleHashCode);
					s_FontAssetRemovalList.Add(s_FontAssetReference.Key);
				}
				else
				{
					fontAsset.InitializeCharacterLookupDictionary();
					fontAsset.AddSynthesizedCharactersAndFaceMetrics();
				}
			}
			for (int i = 0; i < s_FontAssetRemovalList.Count; i++)
			{
				s_FontAssetReferences.Remove(s_FontAssetRemovalList[i]);
			}
			s_FontAssetRemovalList.Clear();
			TMPro_EventManager.ON_FONT_PROPERTY_CHANGED(isChanged: true, null);
		}
	}
