	[Serializable]
	public class TMP_Style
	{
		internal static TMP_Style k_NormalStyle;

		[SerializeField]
		private string m_Name;

		[SerializeField]
		private int m_HashCode;

		[SerializeField]
		private string m_OpeningDefinition;

		[SerializeField]
		private string m_ClosingDefinition;

		[SerializeField]
		private uint[] m_OpeningTagArray;

		[SerializeField]
		private uint[] m_ClosingTagArray;

		public static TMP_Style NormalStyle
		{
			get
			{
				if (k_NormalStyle == null)
				{
					k_NormalStyle = new TMP_Style("Normal", string.Empty, string.Empty);
				}
				return k_NormalStyle;
			}
		}

		public string name
		{
			get
			{
				return m_Name;
			}
			set
			{
				if (value != m_Name)
				{
					m_Name = value;
				}
			}
		}

		public int hashCode
		{
			get
			{
				return m_HashCode;
			}
			set
			{
				if (value != m_HashCode)
				{
					m_HashCode = value;
				}
			}
		}

		public string styleOpeningDefinition => m_OpeningDefinition;

		public string styleClosingDefinition => m_ClosingDefinition;

		public uint[] styleOpeningTagArray => m_OpeningTagArray;

		public uint[] styleClosingTagArray => m_ClosingTagArray;

		internal TMP_Style(string styleName, string styleOpeningDefinition, string styleClosingDefinition)
		{
			m_Name = styleName;
			m_HashCode = TMP_TextParsingUtilities.GetHashCode(styleName);
			m_OpeningDefinition = styleOpeningDefinition;
			m_ClosingDefinition = styleClosingDefinition;
			RefreshStyle();
		}

		public void RefreshStyle()
		{
			m_HashCode = TMP_TextParsingUtilities.GetHashCode(m_Name);
			int length = m_OpeningDefinition.Length;
			m_OpeningTagArray = new uint[length];
			for (int i = 0; i < length; i++)
			{
				m_OpeningTagArray[i] = m_OpeningDefinition[i];
			}
			int length2 = m_ClosingDefinition.Length;
			m_ClosingTagArray = new uint[length2];
			for (int j = 0; j < length2; j++)
			{
				m_ClosingTagArray[j] = m_ClosingDefinition[j];
			}
		}
	}
	[Serializable]
	[ExcludeFromPreset]
	public class TMP_StyleSheet : ScriptableObject
	{
		[SerializeField]
		private List<TMP_Style> m_StyleList = new List<TMP_Style>(1);

		private Dictionary<int, TMP_Style> m_StyleLookupDictionary;

		internal List<TMP_Style> styles => m_StyleList;

		private void Reset()
		{
			LoadStyleDictionaryInternal();
		}

		public TMP_Style GetStyle(int hashCode)
		{
			if (m_StyleLookupDictionary == null)
			{
				LoadStyleDictionaryInternal();
			}
			if (m_StyleLookupDictionary.TryGetValue(hashCode, out var value))
			{
				return value;
			}
			return null;
		}

		public TMP_Style GetStyle(string name)
		{
			if (m_StyleLookupDictionary == null)
			{
				LoadStyleDictionaryInternal();
			}
			int hashCode = TMP_TextParsingUtilities.GetHashCode(name);
			if (m_StyleLookupDictionary.TryGetValue(hashCode, out var value))
			{
				return value;
			}
			return null;
		}

		public void RefreshStyles()
		{
			LoadStyleDictionaryInternal();
		}

		private void LoadStyleDictionaryInternal()
		{
			if (m_StyleLookupDictionary == null)
			{
				m_StyleLookupDictionary = new Dictionary<int, TMP_Style>();
			}
			else
			{
				m_StyleLookupDictionary.Clear();
			}
			for (int i = 0; i < m_StyleList.Count; i++)
			{
				m_StyleList[i].RefreshStyle();
				if (!m_StyleLookupDictionary.ContainsKey(m_StyleList[i].hashCode))
				{
					m_StyleLookupDictionary.Add(m_StyleList[i].hashCode, m_StyleList[i]);
				}
			}
			int hashCode = TMP_TextParsingUtilities.GetHashCode("Normal");
			if (!m_StyleLookupDictionary.ContainsKey(hashCode))
			{
				TMP_Style tMP_Style = new TMP_Style("Normal", string.Empty, string.Empty);
				m_StyleList.Add(tMP_Style);
				m_StyleLookupDictionary.Add(hashCode, tMP_Style);
			}
		}
	}
