			set
			{
				if (value == null)
				{
					ReleaseLinkedTextComponent(m_linkedTextComponent);
					m_linkedTextComponent = value;
				}
				else
				{
					if (IsSelfOrLinkedAncestor(value))
					{
						return;
					}
					ReleaseLinkedTextComponent(m_linkedTextComponent);
					m_linkedTextComponent = value;
					m_linkedTextComponent.parentLinkedComponent = this;
				}
				m_havePropertiesChanged = true;
				SetVerticesDirty();
				SetLayoutDirty();
			}
		}

