			}
			long num2 = (long)num;
			AddIntegerToInternalTextBackingArray(num2, padding, ref writeIndex);
			if (precision <= 0)
			{
				return;
			}
			num -= (decimal)num2;
			if (!(num != 0m))
			{
				return;
			}
			m_TextBackingArray[writeIndex++] = 46u;
			for (int i = 0; i < precision; i++)
			{
				num *= 10m;
				long num3 = (long)num;
				m_TextBackingArray[writeIndex++] = (ushort)(num3 + 48);
				num -= (decimal)num3;
				if (num == 0m)
