				number /= 10.0;
				num++;
			}
			while (number > 0.999999999999999 || num < padding);
			int num3 = num2;
			while (writeIndex + 1 < num2)
			{
				num2--;
				uint value = m_TextBackingArray[writeIndex];
				m_TextBackingArray[writeIndex] = m_TextBackingArray[num2];
				m_TextBackingArray[num2] = value;
				writeIndex++;
			}
			writeIndex = num3;
		}

